INSERT INTO public.spmo_programme_config VALUES (1, 'NSA Corporate Strategy 2025-2030', 'To be the leading smart seaport authority in the region, driving sustainable maritime trade and economic growth by 2030', 'To operate, regulate, and develop world-class port infrastructure and services that connect markets, empower communities, and uphold the highest standards of safety and environmental stewardship', 'SAR', 1, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 5, 10, 5, 3, 5, 5, 85, 5, NULL, NULL);
