INSERT INTO public.spmo_departments VALUES (10, 'Stakeholder Relations & Communications', 'Stakeholder Relations & Communications', '#0284C7', 0, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00');
INSERT INTO public.spmo_pillars VALUES (1, 'Port Operations Excellence', 'Maximise operational efficiency, vessel turnaround, and berth utilisation across all port terminals to deliver best-in-class service levels', 0, '#7C3AED', 'LayoutGrid', 1, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'pillar');
INSERT INTO public.spmo_pillars VALUES (2, 'Maritime Trade & Logistics', 'Grow cargo volumes, diversify trade routes, and position NSA as a premier regional logistics and transshipment hub', 0, '#2563EB', 'LayoutGrid', 2, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'pillar');
INSERT INTO public.spmo_pillars VALUES (3, 'Coastal Commercial Development', 'Unlock the commercial potential of port land and waterfront assets through strategic partnerships, free-zone expansion, and revenue diversification', 0, '#E8590C', 'LayoutGrid', 3, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'pillar');
INSERT INTO public.spmo_pillars VALUES (4, 'Governance & Compliance', 'Strengthen institutional governance frameworks, regulatory compliance, and risk management practices across the authority', 0, '#0D9488', 'LayoutGrid', 4, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'enabler');
INSERT INTO public.spmo_pillars VALUES (5, 'Digital Innovation', 'Accelerate the adoption of smart port technologies, data analytics, and digital platforms to enhance operational and customer outcomes', 0, '#B91C1C', 'LayoutGrid', 5, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'enabler');
INSERT INTO public.spmo_pillars VALUES (6, 'Human Capital', 'Build a high-performing, future-ready maritime workforce through talent development, leadership programmes, and a culture of excellence', 0, '#CA8A04', 'LayoutGrid', 6, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'enabler');
INSERT INTO public.spmo_pillars VALUES (7, 'Financial Sustainability', 'Ensure long-term financial resilience through prudent asset management, cost optimisation, and diversified revenue streams', 0, '#0284C7', 'LayoutGrid', 7, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'enabler');
INSERT INTO public.spmo_pillars VALUES (8, 'Safety & Environment', 'Embed a zero-harm safety culture and achieve measurable environmental targets aligned with international maritime sustainability standards', 0, '#15803D', 'LayoutGrid', 8, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'enabler');
INSERT INTO public.spmo_pillars VALUES (9, 'Stakeholder Engagement', 'Foster trusted relationships with government entities, shipping lines, port users, local communities, and international maritime organisations', 0, '#9333EA', 'LayoutGrid', 9, '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 'enabler');
INSERT INTO public.spmo_initiatives VALUES (1, 1, 'Berth Productivity Optimisation Programme', 'Implement advanced berth scheduling algorithms and real-time vessel traffic management to reduce waiting times and increase berth utilisation rates across all terminals', 'seed', 'PMO Office', '2023-10-01', '2028-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 85000000, 'I-01');
INSERT INTO public.spmo_initiatives VALUES (2, 1, 'Terminal Automation & Smart Gate Deployment', 'Deploy automated gate systems, RFID tracking, and AI-powered truck appointment systems at container and general cargo terminals to eliminate manual bottlenecks', 'seed', 'PMO Office', '2024-01-01', '2028-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 120000000, 'I-02');
INSERT INTO public.spmo_initiatives VALUES (3, 1, 'Port Community System Enhancement', 'Upgrade the national Port Community System to enable seamless data exchange between shipping agents, customs, terminal operators, and logistics providers in real time', 'seed', 'PMO Office', '2023-12-15', '2027-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 45000000, 'I-03');
INSERT INTO public.spmo_initiatives VALUES (4, 2, 'Regional Transshipment Hub Development', 'Develop dedicated transshipment berths and value-added logistics zones to capture regional feeder and mother-vessel traffic on key East-West and North-South trade lanes', 'seed', 'PMO Office', '2024-03-01', '2030-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 210000000, 'I-04');
INSERT INTO public.spmo_initiatives VALUES (5, 2, 'Multimodal Logistics Corridor Initiative', 'Establish integrated road-rail-sea corridors connecting the seaport to inland dry ports, industrial zones, and border crossings to reduce landside logistics costs', 'seed', 'PMO Office', '2024-01-15', '2028-09-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 95000000, 'I-05');
INSERT INTO public.spmo_initiatives VALUES (6, 2, 'Trade Facilitation & Customs Modernisation', 'Partner with the National Customs Authority to implement a single-window clearance platform targeting sub-24-hour import release times for priority cargo categories', 'seed', 'PMO Office', '2024-06-01', '2028-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 65000000, 'I-06');
INSERT INTO public.spmo_initiatives VALUES (7, 3, 'Waterfront Mixed-Use Development Project', 'Master-plan and develop underutilised port waterfront land into a mixed commercial, retail, maritime hospitality, and cruise tourism precinct', 'seed', 'PMO Office', '2023-11-01', '2030-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 150000000, 'I-07');
INSERT INTO public.spmo_initiatives VALUES (8, 3, 'Free Zone Expansion & Investment Attraction', 'Expand the NSA Free Zone footprint by 40% and launch a targeted FDI attraction campaign for maritime manufacturing, ship repair, and logistics tenants', 'seed', 'PMO Office', '2024-02-01', '2029-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 80000000, 'I-08');
INSERT INTO public.spmo_initiatives VALUES (9, 3, 'Ship Repair & Marine Services Cluster', 'Establish a dedicated ship repair and marine services industrial cluster offering dry-dock facilities, engineering services, and OEM spare parts supply chain support', 'seed', 'PMO Office', '2024-04-01', '2028-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 55000000, 'I-09');
INSERT INTO public.spmo_initiatives VALUES (10, 4, 'Enterprise Risk Management Framework Rollout', 'Design and embed a comprehensive ERM framework across all NSA business units with quarterly risk reviews, escalation protocols, and board-level risk appetite statements', 'seed', 'PMO Office', '2024-01-01', '2027-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 35000000, 'I-10');
INSERT INTO public.spmo_initiatives VALUES (11, 4, 'Regulatory Compliance Digitalisation', 'Develop a compliance management system to automate monitoring of SOLAS, MARPOL, ISPS, and local maritime regulatory requirements with real-time dashboards', 'seed', 'PMO Office', '2024-03-15', '2027-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 25000000, 'I-11');
INSERT INTO public.spmo_initiatives VALUES (12, 5, 'Smart Port IoT Platform', 'Deploy a port-wide IoT sensor network covering yard equipment, quay cranes, reefer monitoring, and environmental sensors feeding a unified operational intelligence dashboard', 'seed', 'PMO Office', '2024-05-01', '2028-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 75000000, 'I-12');
INSERT INTO public.spmo_initiatives VALUES (13, 5, 'Cybersecurity Resilience Programme', 'Implement a maritime-sector cybersecurity framework covering OT/IT convergence, threat intelligence sharing, incident response, and crew/staff cyber-awareness training', 'seed', 'PMO Office', '2024-07-01', '2027-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 40000000, 'I-13');
INSERT INTO public.spmo_initiatives VALUES (14, 6, 'Maritime Talent Pipeline Development', 'Launch a structured maritime cadetship, graduate rotational programme, and vocational training partnership with national maritime academies to build a local talent pipeline', 'seed', 'PMO Office', '2024-02-15', '2027-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 30000000, 'I-14');
INSERT INTO public.spmo_initiatives VALUES (15, 6, 'Leadership & Succession Planning Framework', 'Establish a leadership development academy for NSA middle and senior managers incorporating mentoring, executive education partnerships, and formal succession planning', 'seed', 'PMO Office', '2024-04-15', '2028-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 20000000, 'I-15');
INSERT INTO public.spmo_initiatives VALUES (16, 7, 'Capital Investment Optimisation & Project Finance', 'Develop a 10-year capital investment plan with associated project finance structures, including PPP frameworks, green bonds, and multilateral development bank financing', 'seed', 'PMO Office', '2024-06-15', '2030-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 60000000, 'I-16');
INSERT INTO public.spmo_initiatives VALUES (17, 7, 'Revenue Diversification & Port Tariff Reform', 'Conduct a comprehensive tariff benchmarking study and implement a revised port dues and service fee structure to improve competitiveness and grow non-vessel revenue', 'seed', 'PMO Office', '2024-08-01', '2029-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 45000000, 'I-17');
INSERT INTO public.spmo_initiatives VALUES (18, 8, 'Green Port Certification Programme', 'Pursue ISO 14001 and PERS Green Port certification by achieving measurable targets in vessel emissions, shore power provision, waste management, and water quality monitoring', 'seed', 'PMO Office', '2023-10-15', '2028-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 28000000, 'I-18');
INSERT INTO public.spmo_initiatives VALUES (19, 8, 'Alternative Fuels & Clean Energy Infrastructure', 'Develop LNG bunkering facilities and install shore-to-ship power infrastructure at priority berths while piloting hydrogen and ammonia bunkering feasibility studies', 'seed', 'PMO Office', '2024-01-20', '2030-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 90000000, 'I-19');
INSERT INTO public.spmo_initiatives VALUES (20, 9, 'Port User Experience & Stakeholder Portal', 'Launch a unified digital stakeholder portal providing real-time port call status, invoicing, service requests, feedback mechanisms, and regulatory submissions for all port users', 'seed', 'PMO Office', '2024-03-10', '2028-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 35000000, 'I-20');
INSERT INTO public.spmo_initiatives VALUES (21, 9, 'Community Maritime Awareness & CSR Programme', 'Design and deliver annual community engagement campaigns, school maritime education outreach, coastal clean-up initiatives, and local supplier development programmes', 'seed', 'PMO Office', '2024-05-20', '2027-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 20000000, 'I-21');
INSERT INTO public.spmo_initiatives VALUES (22, 1, 'Crane & Yard Equipment Lifecycle Management', 'Implement a predictive maintenance programme for all quay cranes, RTGs, and yard tractors using condition monitoring sensors and AI-driven maintenance scheduling to reduce downtime', 'seed', 'PMO Office', '2024-07-15', '2030-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 18000000, 'I-22');
INSERT INTO public.spmo_initiatives VALUES (23, 2, 'Cruise & Passenger Terminal Development', 'Upgrade the passenger and cruise terminal to international standards including expanded berth capacity, immigration facilities, and landside connectivity to attract homeport cruise lines', 'seed', 'PMO Office', '2024-02-01', '2028-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 110000000, 'I-23');
INSERT INTO public.spmo_initiatives VALUES (24, 3, 'Logistics Real Estate Investment Trust Feasibility', 'Assess the viability of establishing an NSA-sponsored maritime logistics REIT to monetise port-adjacent warehousing and logistics park assets while retaining strategic control', 'seed', 'PMO Office', '2024-04-01', '2029-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 70000000, 'I-24');
INSERT INTO public.spmo_initiatives VALUES (25, 4, 'Board Governance & Performance Management Reform', 'Review and strengthen NSA board composition, committee structures, and executive performance management frameworks in line with international public sector governance standards', 'seed', 'PMO Office', '2024-06-01', '2027-06-30', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 25000000, 'I-25');
INSERT INTO public.spmo_initiatives VALUES (26, 5, 'Port Data Analytics & Decision Intelligence Centre', 'Establish a centralised port analytics centre of excellence leveraging big data, machine learning, and predictive modelling to support operational and strategic decision-making', 'seed', 'PMO Office', '2024-08-15', '2028-12-31', 0, 'active', '2026-03-24 05:25:07.874982+00', '2026-03-24 05:25:07.874982+00', 0, 50000000, 'I-26');
